import Autocomplete from '@mui/material/Autocomplete';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import { Container, display } from '@mui/system';
import Cookies from 'js-cookie';
import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setUser } from '../store/auth.js';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { DesktopDatePicker } from '@mui/x-date-pickers/DesktopDatePicker';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
const InitialForm = {
  label: '',
  icon: '',
};

const icons = ['User'];

export default function CategoryForm({ editCategory }) {
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const token = Cookies.get('token');
  const [form, setForm] = useState(InitialForm);

  useEffect(() => {
    if (editCategory._id !== undefined) {
      setForm(editCategory);
    }
  }, [editCategory]);

  async function fetchFilterList() {
    const token = Cookies.get('token');
    console.log('Hello', JSON.stringify(form));
    const res = await fetch(
      `${process.env.REACT_APP_API_URL}/filter?priceCategory=${
        form.priceRadio
      }&category=${form.category.label || undefined}&sDate=${
        form.sDate
      }&eDate=${form.eDate}`,
      {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      }
    );
  }

  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  function handleStartDate(newValue) {
    setForm({ ...form, sDate: newValue });
  }

  function handleEndDate(newValue) {
    setForm({ ...form, eDate: newValue });
  }

  function handleCategory(newValue) {
    setForm({ ...form, category: newValue });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    console.log('qewqe');
    fetchFilterList();
  }

  function reload(res, _user) {
    if (res.ok) {
      dispatch(setUser({ user: _user }));
      setForm(InitialForm);
    }
  }

  async function create() {
    const res = await fetch(`${process.env.REACT_APP_API_URL}/category`, {
      method: 'POST',
      body: JSON.stringify(form),
      headers: {
        'content-type': 'application/json',
        Authorization: `Bearer ${token}`,
      },
    });

    const _user = {
      ...user,
      categories: [...user.categories, { ...form }],
    };
    reload(res, _user);
  }

  async function update() {
    const res = await fetch(
      `${process.env.REACT_APP_API_URL}/category/${editCategory._id}`,
      {
        method: 'PATCH',
        body: JSON.stringify(form),
        headers: {
          'content-type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
      }
    );
    const _user = {
      ...user,
      categories: user.categories.map((cat) =>
        cat._id == editCategory._id ? form : cat
      ),
    };
    reload(res, _user);
  }

  function getCategoryNameById() {
    return (
      user.categories.find((category) => category._id === form.category_id) ??
      ''
    );
  }

  const Categories = [
    { label: 'All' },
    { label: 'Travel' },
    { label: 'Shopping' },
    { label: 'Misc' },
  ];

  return (
    <Container>
      <Card sx={{ minWidth: 275, marginTop: 10 }}>
        <CardContent>
          <Typography variant='h4'>Filter</Typography>
          <Box
            component='form'
            onSubmit={handleSubmit}
            sx={{ display: 'flex' }}
          >
            {/* <div sx={{ display: 'flex' }}> */}

            {/* <TextField
            sx={{ marginRight: 5 }}
            id='outlined-basic'
            label='Label'
            type='text'
            size='small'
            name='label'
            variant='outlined'
            value={form.label}
            onChange={handleChange}
          /> */}
            {/* <form>
            <div sx={{ width: '20px', display: 'inline-block' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>Less than 1000</span>
            </div>
            <div sx={{ width: '20px', display: 'inline-block' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>1000 - 5000</span>
            </div>
            <div sx={{ width: '20px' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>5000 - 10000</span>
            </div>
            <div sx={{ width: '20px' }}>
              <input type='radio' value='Male' sx={{ margin: '0px' }} />
              <span sx={{ margin: '3px 3px 0px 0' }}>Greater than 10000</span>
            </div>
          </form> */}
            <div sx={{ backgroundColor: 'Blue' }}>
              <form>
                <Typography variant='h6'>Prices</Typography>
                <div className='radio'>
                  <label>
                    <input
                      type='radio'
                      value='option1'
                      name='priceRadio'
                      onChange={handleChange}
                    />
                    Less than 1000
                  </label>
                </div>
                <div className='radio'>
                  <label>
                    <input
                      type='radio'
                      value='option2'
                      name='priceRadio'
                      onChange={handleChange}
                    />
                    1000 - 5000
                  </label>
                </div>
                <div className='radio'>
                  <label>
                    <input
                      type='radio'
                      value='option3'
                      name='priceRadio'
                      onChange={handleChange}
                    />
                    5000 - 10000
                  </label>
                </div>
                <div className='radio'>
                  <label>
                    <input
                      type='radio'
                      value='option4'
                      name='priceRadio'
                      onChange={handleChange}
                    />
                    Greater than 10000
                  </label>
                </div>
              </form>
            </div>
            <div>
              <Typography
                variant='h6'
                sx={{ marginLeft: 10, paddingBottom: 2 }}
              >
                Categories
              </Typography>
              <Autocomplete
                value={JSON.stringify(form.category)}
                // id='category'
                onChange={(event, newValue) => {
                  setForm({ ...form, category: newValue });
                }}
                // onChange={handleCategory}
                options={Categories}
                sx={{ width: 200, marginLeft: 10 }}
                renderInput={(params) => (
                  <TextField {...params} size='small' label='Category' />
                )}
              />
            </div>
            <div>
              <Typography
                variant='h6'
                sx={{ marginLeft: 10, paddingBottom: 2 }}
              >
                Dates
